import os
import json

brain_dir = r"C:\Users\mario\.gemini\antigravity\brain"
print("Scanning all transcripts for Footer contents...")

for root, dirs, files in os.walk(brain_dir):
    for file in files:
        if file in ("transcript_full.jsonl", "transcript.jsonl"):
            filepath = os.path.join(root, file)
            try:
                with open(filepath, "r", encoding="utf-8") as f:
                    for line in f:
                        if "Footer.tsx" in line and "export default function Footer" in line:
                            print(f"FOUND MATCH in {filepath}!")
                            # Save the entire line to a file so we can parse it
                            with open(r"c:\Desarrollo\mmapp\scratch\found_transcript_line.json", "w", encoding="utf-8") as out:
                                out.write(line)
                            print("Saved to found_transcript_line.json")
            except Exception as e:
                pass
print("Done.")
